import{_ as n,o as e,c as t,a2 as i}from"./chunks/framework.CHeM0PsO.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"bantuan.md","filePath":"bantuan.md"}'),r={name:"bantuan.md"};function u(s,a,o,m,d,l){return e(),t("div",null,[...a[0]||(a[0]=[i('<h2 id="bab-14-faq-troubleshooting" tabindex="-1">BAB 14: FAQ &amp; TROUBLESHOOTING <a class="header-anchor" href="#bab-14-faq-troubleshooting" aria-label="Permalink to &quot;BAB 14: FAQ &amp; TROUBLESHOOTING&quot;">​</a></h2><h3 id="untuk-spv" tabindex="-1">Untuk SPV <a class="header-anchor" href="#untuk-spv" aria-label="Permalink to &quot;Untuk SPV&quot;">​</a></h3><p><strong>T: Saya lupa mengatur target omset bulan ini. Apa yang terjadi?</strong> J: Semua persentase pencapaian akan menunjukkan 0%. Segera buka Pengaturan Parameter → Target Omset Bulanan → isi target → Simpan.</p><p><strong>T: Internet mati saat saya menekan tombol &quot;Kirim&quot;. Apakah data saya hilang?</strong> J: Tidak. Data tersimpan otomatis di memori browser HP Anda. Saat internet kembali, buka aplikasi dan tekan &quot;Kirim&quot; lagi. Semua isian masih utuh.</p><p><strong>T: Saya sudah mengirim Fase 1 tadi malam, tapi pagi ini form Fase 2 tidak muncul. Kenapa?</strong> J: Kemungkinan file Draft JSON terhapus dari Google Drive. Sistem akan menampilkan pesan yang meminta Anda membuat ulang laporan dari awal. Hubungi owner jika masalah berlanjut.</p><p><strong>T: Nama staf yang saya cari tidak muncul di dropdown. Kenapa?</strong> J: Kemungkinan staf belum terdaftar atau sudah berstatus &quot;Resign&quot; di database. Buka Pengaturan Parameter → Kelola Staf Outlet untuk menambahkan.</p><p><strong>T: Saya tidak sengaja mengirim laporan 2 kali. Apakah data jadi double?</strong> J: Tidak. Sistem memiliki perlindungan anti-duplikasi. Jika Anda mengirim laporan dengan tanggal dan outlet yang sama, pengiriman kedua akan ditolak otomatis.</p><p><strong>T: Saya login sebagai SPV Perintis, tapi data yang muncul adalah data Dg Tata dari kemarin. Kenapa?</strong> J: Sistem sudah memiliki perlindungan ini. Saat Anda login, sistem otomatis membuang data yang tidak cocok dengan outlet Anda. Jika masih terjadi, coba hapus data browser (Clear Cache) dan login ulang.</p><h3 id="untuk-gm-owner" tabindex="-1">Untuk GM / Owner <a class="header-anchor" href="#untuk-gm-owner" aria-label="Permalink to &quot;Untuk GM / Owner&quot;">​</a></h3><p><strong>T: Dashboard tidak menampilkan data sama sekali (&quot;Belum ada data&quot;). Kenapa?</strong> J: Pastikan SPV sudah mengirim minimal 1 laporan harian di rentang waktu yang Anda pilih. Periksa juga apakah filter outlet sudah benar.</p><p><strong>T: Persentase target omset selalu 0% padahal ada penjualan. Kenapa?</strong> J: SPV belum mengatur Target Omset Bulanan di menu Pengaturan Parameter. Ingatkan SPV untuk mengisinya di awal setiap bulan.</p><p><strong>T: Saya ingin melihat data setahun penuh, tapi beberapa grafik tidak muncul. Kenapa?</strong> J: Saat Anda memilih rentang &gt; 95 hari, sistem masuk ke Mode Strategis yang otomatis menyembunyikan beberapa analisis detail (seperti Minus Kas per staf dan Revenue per SPV). Ini disengaja agar data tahunan tidak terlalu bising.</p><p><strong>T: Di mana saya bisa melihat file PDF laporan SPV?</strong> J: Buka accordion &quot;Arsip Laporan PDF&quot; di bagian bawah Dashboard. Atau langsung buka Google Drive folder <code>Zero Cafe Workspace Drive &gt; [Tahun] &gt; [Bulan] &gt; [Outlet]</code>.</p><p><strong>T: Bagaimana cara mengubah folder penyimpanan di Google Drive?</strong> J: Di Dashboard GM, buka Pengaturan → masukkan ID Folder baru → Simpan. Semua file baru akan otomatis masuk ke folder tersebut.</p><hr><h2 id="catatan-penutup" tabindex="-1">Catatan Penutup <a class="header-anchor" href="#catatan-penutup" aria-label="Permalink to &quot;Catatan Penutup&quot;">​</a></h2><p>Buku Panduan ini adalah <strong>dokumen hidup</strong> yang akan terus diperbarui seiring dengan evolusi aplikasi Zero Cafe. Setiap penambahan fitur besar atau perubahan arsitektur akan secara otomatis didokumentasikan di sini.</p><p>Jika Anda memiliki pertanyaan, masukan, atau menemukan ketidaksesuaian antara panduan ini dengan perilaku aplikasi, silakan hubungi tim pengembang:</p><p><strong>Acronimous Studio</strong><em>Membangun Sistem Cerdas untuk Bisnis Lokal</em></p><hr><p><em>Dokumen ini disusun sebagai bagian dari proyek Zero Cafe Workspace oleh Acronimous Studio. Seluruh hak cipta dilindungi.</em><em>Versi 2.1 — Checkpoint 20 — Juli 2026</em></p>',21)])])}const k=n(r,[["render",u]]);export{g as __pageData,k as default};
